import React, { useState, useEffect } from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { 
    LayoutDashboard, PackageSearch, BrainCircuit, FlaskConical, LineChart, 
    Settings, ScanBarcode, Calculator, TrendingUp, Zap, ShoppingCart, 
    Wallet, ShieldCheck, BarChart4, ChevronDown, ChevronRight, Boxes,
    PieChart, Landmark, CircleDollarSign, GitCommit, LayoutGrid
} from 'lucide-react';

export const Sidebar: React.FC = () => {
  const location = useLocation();
  const [openGroups, setOpenGroups] = useState<string[]>([]);

  // Auto-open groups if active route is inside them
  useEffect(() => {
    const operationPaths = ['/inventory', '/inventory-control', '/production'];
    const planningPaths = ['/forecast', '/purchasing', '/action-center'];
    const financePaths = ['/financial', '/governance', '/intelligence', '/analytics', '/event-log'];
    const salesPaths = ['/sales-performance', '/atp'];

    setOpenGroups(prev => {
        const newGroups = [...prev];
        if (operationPaths.includes(location.pathname) && !newGroups.includes('Operación')) {
            newGroups.push('Operación');
        }
        if (planningPaths.includes(location.pathname) && !newGroups.includes('Planificación & Optimización')) {
            newGroups.push('Planificación & Optimización');
        }
        if (financePaths.includes(location.pathname) && !newGroups.includes('Finanzas & Inteligencia')) {
            newGroups.push('Finanzas & Inteligencia');
        }
        if (salesPaths.includes(location.pathname) && !newGroups.includes('Ventas & Ingresos')) {
            newGroups.push('Ventas & Ingresos');
        }
        return newGroups;
    });
  }, [location.pathname]);

  const toggleGroup = (groupLabel: string) => {
    setOpenGroups(prev => 
        prev.includes(groupLabel) 
        ? prev.filter(g => g !== groupLabel) 
        : [...prev, groupLabel]
    );
  };

  const navStructure = [
    { type: 'item', to: "/", icon: LayoutDashboard, label: "Tablero Principal" },
    // New Smart View Button - Gamified/Visual Mode
    { type: 'item', to: "/smart-view", icon: LayoutGrid, label: "Smart View ✦", special: true },

    // Group: Sales & Revenue
    {
        type: 'group',
        label: "Ventas & Ingresos",
        icon: CircleDollarSign,
        children: [
            { to: "/sales-performance", icon: BarChart4, label: "Sales Performance" },
            { to: "/atp", icon: Calculator, label: "ATP y Asignación" },
        ]
    },

    // Group: Operation
    {
        type: 'group',
        label: "Operación",
        icon: Boxes,
        children: [
            { to: "/inventory", icon: PackageSearch, label: "Inventario Maestro" },
            { to: "/inventory-control", icon: ScanBarcode, label: "Control de Inventario (Deep)" },
            { to: "/production", icon: FlaskConical, label: "Producción y Lotes" },
        ]
    },

    // Group: Planning & Optimization
    {
        type: 'group',
        label: "Planificación & Optimización",
        icon: TrendingUp,
        children: [
            { to: "/forecast", icon: PieChart, label: "Forecast & Planning" },
            { to: "/purchasing", icon: ShoppingCart, label: "Purchasing Intelligence" },
            { to: "/action-center", icon: Zap, label: "Inventory Drain / Actions" },
        ]
    },

    // Group: Finance & Intelligence
    {
        type: 'group',
        label: "Finanzas & Inteligencia",
        icon: Landmark,
        children: [
            { to: "/financial", icon: Wallet, label: "Impacto Financiero" },
            { to: "/intelligence", icon: BrainCircuit, label: "Inteligencia Artificial" },
            { to: "/analytics", icon: LineChart, label: "Analítica Avanzada" },
            { to: "/governance", icon: ShieldCheck, label: "Data Governance" },
            { to: "/event-log", icon: GitCommit, label: "Bitácora de Eventos" },
        ]
    },
  ];

  return (
    <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col h-screen sticky top-0 z-50">
      <div className="p-6 border-b border-slate-800">
        <div className="flex items-center gap-2 text-white">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center">
            <span className="font-bold text-lg">P</span>
          </div>
          <span className="font-bold text-xl tracking-tight">Procoquinal OS</span>
        </div>
      </div>

      <nav className="flex-1 p-4 space-y-1 overflow-y-auto custom-scrollbar">
        {navStructure.map((item, index) => {
            if (item.type === 'group' && item.children) {
                const isOpen = openGroups.includes(item.label);
                const isChildActive = item.children.some(child => child.to === location.pathname);

                return (
                    <div key={index} className="mb-1">
                        <button 
                            onClick={() => toggleGroup(item.label)}
                            className={`w-full flex items-center justify-between px-4 py-3 text-sm font-medium rounded-lg transition-colors ${
                                isChildActive ? 'text-white bg-slate-800' : 'hover:bg-slate-800 hover:text-white'
                            }`}
                        >
                            <div className="flex items-center">
                                {item.icon && <item.icon className="w-5 h-5 mr-3" />}
                                {item.label}
                            </div>
                            {isOpen ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />}
                        </button>

                        {isOpen && (
                            <div className="mt-1 space-y-1 pl-4 relative">
                                <div className="absolute left-6 top-0 bottom-0 w-px bg-slate-800"></div>
                                {item.children.map((child) => (
                                    <NavLink
                                        key={child.to}
                                        to={child.to}
                                        className={({ isActive }) =>
                                        `flex items-center px-4 py-2.5 text-sm font-medium rounded-lg transition-all relative z-10 ${
                                            isActive
                                            ? "bg-blue-600 text-white shadow-lg shadow-blue-900/50"
                                            : "text-slate-400 hover:text-white hover:bg-slate-800/50"
                                        }`
                                        }
                                    >
                                        <child.icon className="w-4 h-4 mr-3" />
                                        {child.label}
                                    </NavLink>
                                ))}
                            </div>
                        )}
                    </div>
                );
            } else {
                // Regular Item
                const isSpecial = (item as any).special;
                return (
                    <NavLink
                        key={item.to}
                        to={item.to!}
                        className={({ isActive }) =>
                        `flex items-center px-4 py-3 text-sm font-medium rounded-lg transition-all ${
                            isActive
                            ? isSpecial 
                                ? "bg-gradient-to-r from-indigo-500 to-purple-600 text-white shadow-lg shadow-indigo-500/30" 
                                : "bg-blue-600 text-white shadow-lg shadow-blue-900/50"
                            : isSpecial
                                ? "text-indigo-300 hover:text-white hover:bg-indigo-900/30 border border-indigo-500/30 my-2"
                                : "hover:bg-slate-800 hover:text-white"
                        }`
                        }
                    >
                        {item.icon && <item.icon className={`w-5 h-5 mr-3 ${isSpecial ? 'animate-pulse' : ''}`} />}
                        {item.label}
                    </NavLink>
                );
            }
        })}
      </nav>

      <div className="p-4 border-t border-slate-800">
        <button className="flex items-center px-4 py-3 w-full text-sm font-medium text-slate-400 hover:text-white hover:bg-slate-800 rounded-lg transition-colors">
            <Settings className="w-5 h-5 mr-3" />
            Configuración
        </button>
        <div className="mt-4 px-4">
             <div className="text-xs text-slate-500 uppercase font-bold tracking-wider mb-2">Estado del Sistema</div>
             <div className="flex items-center gap-2 text-xs text-emerald-400">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                ERP Conectado
             </div>
        </div>
      </div>
    </aside>
  );
};

import React, { useState, useMemo } from 'react';
import { MOCK_INVENTORY } from '../constants';
import { InventoryStatus, ABCClass, XYZClass } from '../types';
import { 
    Search, Filter, Layers, Box, Cpu, Activity, Zap, 
    Droplet, ShieldCheck, Ghost, AlertTriangle, ArrowUpRight
} from 'lucide-react';

const Card = ({ product }: { product: any }) => {
    // Logic for Gamified Visuals
    const atp = product.totalStock - product.reservedStock;
    const atpPercent = Math.min(100, (atp / product.totalStock) * 100);
    const value = (product.category === 'Materia Prima' ? product.unitCost : product.price) * product.totalStock;

    // Determine "Health Score" (0-100)
    let healthScore = 100;
    if (product.status === InventoryStatus.SLOW) healthScore -= 30;
    if (product.status === InventoryStatus.SILENT) healthScore -= 60;
    if (product.agingDays > 90) healthScore -= 20;
    if (atp < 0) healthScore = 0;

    const healthColor = healthScore > 80 ? 'bg-emerald-500' : healthScore > 50 ? 'bg-amber-500' : 'bg-rose-500';
    const shadowColor = healthScore > 80 ? 'shadow-emerald-200' : healthScore > 50 ? 'shadow-amber-200' : 'shadow-rose-200';

    return (
        <div className={`group relative bg-white/70 backdrop-blur-xl border border-white/50 rounded-3xl p-5 hover:-translate-y-2 transition-all duration-300 shadow-xl ${shadowColor} hover:shadow-2xl`}>
            {/* Background Gradient Blob */}
            <div className={`absolute -top-10 -right-10 w-24 h-24 rounded-full blur-3xl opacity-20 group-hover:opacity-40 transition-opacity ${healthColor}`}></div>

            {/* Header: Class & Icon */}
            <div className="flex justify-between items-start mb-4">
                <div className="flex items-center gap-2">
                    <div className="p-2.5 bg-slate-50 border border-slate-100 rounded-2xl shadow-inner text-slate-600 group-hover:scale-110 transition-transform">
                        {product.category === 'Materia Prima' ? <Box className="w-6 h-6" /> : <Droplet className="w-6 h-6" />}
                    </div>
                    <div>
                        <div className="flex items-center gap-1">
                            <span className="text-[10px] font-bold bg-slate-900 text-white px-1.5 py-0.5 rounded uppercase tracking-wider">
                                {product.abc}{product.xyz}
                            </span>
                            {product.status === InventoryStatus.SILENT && (
                                <span className="text-[10px] font-bold bg-rose-100 text-rose-600 px-1.5 py-0.5 rounded border border-rose-200 flex items-center">
                                    <Ghost className="w-3 h-3 mr-1" /> GHOST
                                </span>
                            )}
                        </div>
                    </div>
                </div>

                {/* Health Orb */}
                <div className="relative">
                    <div className={`w-3 h-3 rounded-full ${healthColor} animate-pulse`}></div>
                    <div className={`absolute top-0 left-0 w-3 h-3 rounded-full ${healthColor} blur-sm`}></div>
                </div>
            </div>

            {/* Content: Title & SKU */}
            <h3 className="font-bold text-slate-800 text-lg leading-tight mb-1 truncate" title={product.name}>
                {product.name}
            </h3>
            <p className="text-xs text-slate-400 font-mono mb-4">{product.sku}</p>

            {/* Visual Stats: Stock Bar */}
            <div className="space-y-1 mb-4">
                <div className="flex justify-between text-xs font-semibold text-slate-500">
                    <span>Nivel ATP</span>
                    <span className={atp < 0 ? 'text-rose-500' : 'text-slate-700'}>{atp} / {product.totalStock}</span>
                </div>
                <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden border border-slate-200">
                    <div 
                        className={`h-full rounded-full transition-all duration-1000 ease-out ${
                            product.status === InventoryStatus.SILENT ? 'bg-slate-300' : 'bg-gradient-to-r from-blue-500 to-indigo-600'
                        }`} 
                        style={{ width: `${Math.max(0, atpPercent)}%` }}
                    ></div>
                </div>
            </div>

            {/* Footer Grid */}
            <div className="grid grid-cols-2 gap-2 mt-4 pt-4 border-t border-slate-100/80">
                <div className="bg-slate-50 rounded-xl p-2 text-center border border-slate-100">
                    <div className="text-[10px] text-slate-400 uppercase font-bold">Valor Total</div>
                    <div className="text-sm font-bold text-slate-700">${(value/1000).toFixed(1)}k</div>
                </div>
                <div className={`rounded-xl p-2 text-center border ${
                    product.agingDays > 60 ? 'bg-rose-50 border-rose-100' : 'bg-emerald-50 border-emerald-100'
                }`}>
                    <div className={`text-[10px] uppercase font-bold ${
                        product.agingDays > 60 ? 'text-rose-400' : 'text-emerald-400'
                    }`}>Aging</div>
                    <div className={`text-sm font-bold ${
                        product.agingDays > 60 ? 'text-rose-600' : 'text-emerald-600'
                    }`}>{product.agingDays}d</div>
                </div>
            </div>

            {/* Hover Action (Simulated) */}
            <div className="absolute inset-0 bg-white/60 backdrop-blur-sm opacity-0 group-hover:opacity-100 transition-opacity duration-200 rounded-3xl flex flex-col items-center justify-center gap-2 pointer-events-none group-hover:pointer-events-auto">
                <button className="px-4 py-2 bg-slate-900 text-white rounded-full text-xs font-bold shadow-lg hover:scale-105 transition-transform flex items-center">
                    <Activity className="w-3 h-3 mr-2" /> Analizar
                </button>
                <button className="px-4 py-2 bg-white text-slate-700 border border-slate-200 rounded-full text-xs font-bold shadow-lg hover:scale-105 transition-transform">
                    Ver Lotes
                </button>
            </div>
        </div>
    );
};

export const SmartInventoryView: React.FC = () => {
    const [filter, setFilter] = useState('ALL');
    const [search, setSearch] = useState('');

    const filteredData = useMemo(() => {
        return MOCK_INVENTORY.filter(item => {
            const matchesFilter = filter === 'ALL' || item.status === filter || item.abc === filter;
            const matchesSearch = item.name.toLowerCase().includes(search.toLowerCase()) || item.sku.toLowerCase().includes(search.toLowerCase());
            return matchesFilter && matchesSearch;
        });
    }, [filter, search]);

    return (
        <div className="min-h-screen bg-slate-50 relative overflow-hidden">
            {/* Background Ambiance */}
            <div className="absolute top-0 left-0 w-full h-96 bg-gradient-to-b from-indigo-50 to-transparent pointer-events-none"></div>
            <div className="absolute top-20 right-20 w-64 h-64 bg-purple-200/20 rounded-full blur-3xl pointer-events-none"></div>
            <div className="absolute top-40 left-10 w-96 h-96 bg-blue-200/20 rounded-full blur-3xl pointer-events-none"></div>

            <div className="relative z-10 p-8 h-screen overflow-y-auto custom-scrollbar">

                {/* HUD Header */}
                <header className="flex flex-col md:flex-row justify-between items-center mb-10 gap-6">
                    <div>
                        <h1 className="text-4xl font-black text-transparent bg-clip-text bg-gradient-to-r from-slate-900 to-slate-600 flex items-center gap-3">
                            <Cpu className="w-8 h-8 text-slate-800" />
                            Smart View <span className="text-lg font-light text-slate-400">| Visión Holográfica</span>
                        </h1>
                        <p className="text-slate-500 mt-2 font-medium">
                            {filteredData.length} Activos Digitales • <span className="text-emerald-500">Sistema Online</span>
                        </p>
                    </div>

                    {/* HUD Controls */}
                    <div className="flex items-center gap-4 bg-white/80 backdrop-blur-md p-2 rounded-2xl border border-white shadow-lg shadow-slate-200/50">
                        <div className="relative group">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
                            <input 
                                type="text" 
                                placeholder="Escanear SKU..." 
                                value={search}
                                onChange={(e) => setSearch(e.target.value)}
                                className="pl-9 pr-4 py-2.5 bg-transparent text-sm font-medium text-slate-700 outline-none w-48 focus:w-64 transition-all placeholder:text-slate-400"
                            />
                        </div>
                        <div className="h-6 w-px bg-slate-200 mx-1"></div>
                        <div className="flex gap-1">
                            {['ALL', 'Activo', 'Silencioso', 'A'].map((f) => (
                                <button
                                    key={f}
                                    onClick={() => setFilter(f)}
                                    className={`px-3 py-1.5 rounded-xl text-xs font-bold transition-all ${
                                        filter === f 
                                        ? 'bg-slate-900 text-white shadow-md' 
                                        : 'text-slate-500 hover:bg-slate-100'
                                    }`}
                                >
                                    {f === 'A' ? 'Clase A' : f === 'ALL' ? 'Todo' : f}
                                </button>
                            ))}
                        </div>
                    </div>
                </header>

                {/* Grid Layout */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-6 pb-20">
                    {filteredData.map((product, idx) => (
                        <div key={product.id} className="animate-in fade-in zoom-in duration-500" style={{ animationDelay: `${idx * 50}ms` }}>
                            <Card product={product} />
                        </div>
                    ))}
                </div>

                {/* Empty State */}
                {filteredData.length === 0 && (
                    <div className="flex flex-col items-center justify-center h-64 text-slate-400">
                        <Layers className="w-16 h-16 mb-4 opacity-20" />
                        <p className="text-lg font-light">No se encontraron activos en el rango de escaneo.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './components/Dashboard';
import { InventoryTable } from './components/InventoryTable';
