const App: React.FC = () => {
  return (
    <HashRouter>
      <div className="flex min-h-screen bg-slate-50 font-sans">
        <Sidebar />
        <main className="flex-1 overflow-y-auto h-screen relative">
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/smart-view" element={<SmartInventoryView />} />
            <Route path="/sales-performance" element={<SalesPerformance />} />
            <Route path="/financial" element={<FinancialImpact />} />
            <Route path="/forecast" element={<ForecastPlanning />} />
            <Route path="/purchasing" element={<PurchasingIntelligence />} />
            <Route path="/action-center" element={<ActionCenter />} />
            <Route path="/inventory" element={<InventoryTable />} />
            <Route path="/inventory-control" element={<InventoryControlDeep />} />
            <Route path="/production" element={<ProductionManagement />} />
            <Route path="/atp" element={<ATPAllocation />} />
            <Route path="/governance" element={<DataGovernance />} />
            <Route path="/intelligence" element={<IntelligenceHub />} />
            <Route path="/analytics" element={<AdvancedAnalytics />} />
            <Route path="/event-log" element={<EventLog />} />
