  const hasRunAutoPrompt = useRef(false);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Handle auto-prompt from navigation (e.g. from Smart View)
  useEffect(() => {
    if (location.state?.autoPrompt && !hasRunAutoPrompt.current) {
        hasRunAutoPrompt.current = true;
        const prompt = location.state.autoPrompt;

        // Add user message immediately
        setMessages(prev => [...prev, { role: 'user', content: prompt }]);
        setLoading(true);

        // Execute AI
        generateInsight(prompt).then(response => {
             setMessages(prev => [...prev, { role: 'system', content: response }]);
             setLoading(false);
        });

        // Clear history state so refresh doesn't re-trigger
        window.history.replaceState({}, '');
    }
  }, [location.state]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: Message = { role: 'user', content: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const response = await generateInsight(input);

    setMessages(prev => [...prev, { role: 'system', content: response }]);
    setLoading(false);
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const suggestions = [
    "Identificar riesgos de inventario silencioso",
    "¿Qué productos tienen mejor rendimiento (ABC)?",
    "Sugerir estrategia de bundles para ítems lentos",
    "Calcular salud del inventario"
  ];

  return (
    <div className="flex flex-col h-[calc(100vh-2rem)] m-4 bg-white rounded-2xl shadow-lg border border-slate-200 overflow-hidden">
        {/* Header */}
        <div className="p-4 bg-slate-900 text-white flex items-center justify-between">
            <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-500 rounded-lg">
                    <Sparkles className="w-5 h-5 text-white" />
                </div>
                <div>
                    <h2 className="font-semibold text-lg">Inteligencia del Sistema</h2>
                    <p className="text-xs text-slate-400">Potenciado por Gemini AI • Conectado al ERP</p>
                </div>
            </div>
        </div>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50">
            {messages.map((msg, idx) => (
                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`flex gap-3 max-w-[80%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                        <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${msg.role === 'user' ? 'bg-indigo-600' : 'bg-emerald-600'}`}>
                            {msg.role === 'user' ? <User className="w-5 h-5 text-white" /> : <Bot className="w-5 h-5 text-white" />}
                        </div>
                        <div className={`p-4 rounded-2xl shadow-sm whitespace-pre-line text-sm leading-relaxed ${
                            msg.role === 'user' 
                            ? 'bg-indigo-600 text-white rounded-tr-none' 
                            : 'bg-white text-slate-700 border border-slate-200 rounded-tl-none'
                        }`}>
                            {msg.content}
                        </div>
                    </div>
                </div>
            ))}
            {loading && (
                 <div className="flex justify-start">
                    <div className="flex gap-3 max-w-[80%]">
                        <div className="w-8 h-8 rounded-full bg-emerald-600 flex items-center justify-center flex-shrink-0">
                            <Bot className="w-5 h-5 text-white" />
                        </div>
                        <div className="bg-white p-4 rounded-2xl rounded-tl-none border border-slate-200 shadow-sm flex items-center gap-2">
                            <Loader2 className="w-4 h-4 text-slate-400 animate-spin" />
                            <span className="text-sm text-slate-500">Analizando datos del sistema...</span>
                        </div>
                    </div>
                 </div>
            )}
            <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 bg-white border-t border-slate-200">
             {messages.length === 1 && (
                <div className="mb-4 flex flex-wrap gap-2">
                    {suggestions.map(s => (
                        <button 
                            key={s} 
                            onClick={() => { setInput(s); }}
                            className="text-xs px-3 py-1.5 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-full transition-colors border border-slate-200"
                        >
                            {s}
                        </button>
                    ))}
                </div>
            )}
            <div className="relative">
                <textarea 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={handleKeyPress}
                    placeholder="Pregunta sobre inventario, tendencias de ventas o producción..."
                    className="w-full pl-4 pr-12 py-3 bg-slate-50 border border-slate-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent resize-none text-sm"
                    rows={2}
                />
                <button 
                    onClick={handleSend}
                    disabled={!input.trim() || loading}
                    className="absolute right-2 top-2 p-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                >
                    <Send className="w-4 h-4" />
                </button>
            </div>
            <p className="text-center text-xs text-slate-400 mt-2">La IA puede cometer errores. Verifica decisiones críticas de inventario.</p>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { 
    LayoutDashboard, PackageSearch, BrainCircuit, FlaskConical, LineChart, 
    Settings, ScanBarcode, Calculator, TrendingUp, Zap, ShoppingCart, 
    Wallet, ShieldCheck, BarChart4, ChevronDown, ChevronRight, Boxes,
    PieChart, Landmark, CircleDollarSign, GitCommit, LayoutGrid, Users, Briefcase
} from 'lucide-react';

export const Sidebar: React.FC = () => {
  const location = useLocation();
  const [openGroups, setOpenGroups] = useState<string[]>([]);

  // Auto-open groups if active route is inside them
  useEffect(() => {
    const operationPaths = ['/inventory', '/inventory-control', '/production'];
    const planningPaths = ['/forecast', '/purchasing', '/action-center'];
    const financePaths = ['/financial', '/governance', '/intelligence', '/analytics', '/event-log'];
    const salesPaths = ['/sales-performance', '/atp'];
    const staffPaths = ['/staff/sales-profiles'];

    setOpenGroups(prev => {
        const newGroups = [...prev];
        if (operationPaths.includes(location.pathname) && !newGroups.includes('Operación')) {
            newGroups.push('Operación');
        }
        if (planningPaths.includes(location.pathname) && !newGroups.includes('Planificación & Optimización')) {
            newGroups.push('Planificación & Optimización');
        }
        if (financePaths.includes(location.pathname) && !newGroups.includes('Finanzas & Inteligencia')) {
            newGroups.push('Finanzas & Inteligencia');
        }
        if (salesPaths.includes(location.pathname) && !newGroups.includes('Ventas & Ingresos')) {
            newGroups.push('Ventas & Ingresos');
        }
        if (staffPaths.includes(location.pathname) && !newGroups.includes('Staff & Talento')) {
            newGroups.push('Staff & Talento');
        }
        return newGroups;
    });
  }, [location.pathname]);

  const toggleGroup = (groupLabel: string) => {
    setOpenGroups(prev => 
        prev.includes(groupLabel) 
        ? prev.filter(g => g !== groupLabel) 
        : [...prev, groupLabel]
    );
  };

  const navStructure = [
    { type: 'item', to: "/", icon: LayoutDashboard, label: "Tablero Principal" },

    // Group: Sales & Revenue
    {
        type: 'group',
        label: "Ventas & Ingresos",
        icon: CircleDollarSign,
        children: [
            { to: "/sales-performance", icon: BarChart4, label: "Sales Performance" },
            { to: "/atp", icon: Calculator, label: "ATP y Asignación" },
        ]
    },

    // Group: Operation
    {
        type: 'group',
        label: "Operación",
        icon: Boxes,
        children: [
            { to: "/inventory", icon: PackageSearch, label: "Inventario Maestro" },
            { to: "/inventory-control", icon: ScanBarcode, label: "Control de Inventario (Deep)" },
            { to: "/production", icon: FlaskConical, label: "Producción y Lotes" },
        ]
    },

    // Group: Planning & Optimization
    {
        type: 'group',
        label: "Planificación & Optimización",
        icon: TrendingUp,
        children: [
            { to: "/forecast", icon: PieChart, label: "Forecast & Planning" },
            { to: "/purchasing", icon: ShoppingCart, label: "Purchasing Intelligence" },
            { to: "/action-center", icon: Zap, label: "Inventory Drain / Actions" },
        ]
    },

    // Group: Finance & Intelligence
    {
        type: 'group',
        label: "Finanzas & Inteligencia",
        icon: Landmark,
        children: [
            { to: "/financial", icon: Wallet, label: "Impacto Financiero" },
            { to: "/intelligence", icon: BrainCircuit, label: "Inteligencia Artificial" },
            { to: "/analytics", icon: LineChart, label: "Analítica Avanzada" },
            { to: "/governance", icon: ShieldCheck, label: "Data Governance" },
            { to: "/event-log", icon: GitCommit, label: "Bitácora de Eventos" },
        ]
    },

    // Group: Staff
    {
        type: 'group',
        label: "Staff & Talento",
        icon: Users,
        children: [
            { to: "/staff/sales-profiles", icon: Briefcase, label: "Gestión Comercial" },
        ]
    },
  ];

  return (
    <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col h-screen sticky top-0 z-50">
      <div className="p-6 border-b border-slate-800">
        <div className="flex items-center gap-2 text-white">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center">
            <span className="font-bold text-lg">P</span>
          </div>
          <span className="font-bold text-xl tracking-tight">Procoquinal OS</span>
        </div>
      </div>

      <nav className="flex-1 p-4 space-y-1 overflow-y-auto custom-scrollbar">
        {navStructure.map((item, index) => {
            if (item.type === 'group' && item.children) {
                const isOpen = openGroups.includes(item.label);
                const isChildActive = item.children.some(child => child.to === location.pathname);

                return (
                    <div key={index} className="mb-1">
                        <button 
                            onClick={() => toggleGroup(item.label)}
                            className={`w-full flex items-center justify-between px-4 py-3 text-sm font-medium rounded-lg transition-colors ${
                                isChildActive ? 'text-white bg-slate-800' : 'hover:bg-slate-800 hover:text-white'
                            }`}
                        >
                            <div className="flex items-center">
                                {item.icon && <item.icon className="w-5 h-5 mr-3" />}
                                {item.label}
                            </div>
                            {isOpen ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />}
                        </button>

                        {isOpen && (
                            <div className="mt-1 space-y-1 pl-4 relative">
                                <div className="absolute left-6 top-0 bottom-0 w-px bg-slate-800"></div>
                                {item.children.map((child) => (
                                    <NavLink
                                        key={child.to}
                                        to={child.to}
                                        className={({ isActive }) =>
                                        `flex items-center px-4 py-2.5 text-sm font-medium rounded-lg transition-all relative z-10 ${
                                            isActive
                                            ? "bg-blue-600 text-white shadow-lg shadow-blue-900/50"
                                            : "text-slate-400 hover:text-white hover:bg-slate-800/50"
                                        }`
                                        }
                                    >
                                        <child.icon className="w-4 h-4 mr-3" />
                                        {child.label}
                                    </NavLink>
                                ))}
                            </div>
                        )}
                    </div>
                );
            } else {
                // Regular Item
                const isSpecial = (item as any).special;
                return (
                    <NavLink
                        key={item.to}
                        to={item.to!}
                        className={({ isActive }) =>
                        `flex items-center px-4 py-3 text-sm font-medium rounded-lg transition-all ${
                            isActive
                            ? isSpecial 
                                ? "bg-gradient-to-r from-indigo-500 to-purple-600 text-white shadow-lg shadow-indigo-500/30" 
                                : "bg-blue-600 text-white shadow-lg shadow-blue-900/50"
                            : isSpecial
                                ? "text-indigo-300 hover:text-white hover:bg-indigo-900/30 border border-indigo-500/30 my-2"
                                : "hover:bg-slate-800 hover:text-white"
                        }`
                        }
                    >
                        {item.icon && <item.icon className={`w-5 h-5 mr-3 ${isSpecial ? 'animate-pulse' : ''}`} />}
                        {item.label}
                    </NavLink>
                );
            }
        })}
      </nav>

      <div className="p-4 border-t border-slate-800 space-y-2">
        <NavLink
            to="/smart-view"
            className={({ isActive }) =>
            `flex items-center px-4 py-3 text-sm font-medium rounded-lg transition-all ${
                isActive
                ? "bg-gradient-to-r from-indigo-500 to-purple-600 text-white shadow-lg shadow-indigo-500/30" 
                : "text-indigo-300 hover:text-white hover:bg-indigo-900/30 border border-indigo-500/30"
            }`
            }
        >
            <LayoutGrid className="w-5 h-5 mr-3 animate-pulse" />
            Smart View ✦
        </NavLink>

        <button className="flex items-center px-4 py-3 w-full text-sm font-medium text-slate-400 hover:text-white hover:bg-slate-800 rounded-lg transition-colors">
            <Settings className="w-5 h-5 mr-3" />
            Configuración
        </button>
        <div className="mt-4 px-4">
             <div className="text-xs text-slate-500 uppercase font-bold tracking-wider mb-2">Estado del Sistema</div>
             <div className="flex items-center gap-2 text-xs text-emerald-400">
                <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                ERP Conectado
             </div>
        </div>
      </div>
    </aside>
  );
};

